class Solution {
    public int[] smallestTrimmedNumbers(String[] nums, int[][] queries) {
        int n = nums.length;
        int m = queries.length;
        int[] ans = new int[m];
        int len = nums[0].length();

        for (int q = 0; q < m; q++) {
            int k = queries[q][0];
            int trim = queries[q][1];

            int[][] arr = new int[n][2];
            for (int i = 0; i < n; i++) {
                String s = nums[i].substring(len - trim);
                arr[i][0] = Integer.parseInt(s);
                arr[i][1] = i;
            }

            java.util.Arrays.sort(arr, (a, b) -> {
                if (a[0] != b[0]) return Integer.compare(a[0], b[0]);
                return Integer.compare(a[1], b[1]);
            });

            ans[q] = arr[k - 1][1];
        }
        return ans;
    }
}
```
